// components/ShowForm.js
// Formulário para cadastrar um novo show.
// Usa useState para controlar os campos do formulário.

import { useState } from 'react';
import { createShow } from '../services/api';

export default function ShowForm({ onShowCriado }) {
  // Estado do formulário — cada campo é uma propriedade
  const [form, setForm] = useState({
    data: '',
    valorCache: '',
    local: '',
    observacoes: '',
  });

  const [loading, setLoading] = useState(false);
  const [erro, setErro] = useState('');
  const [sucesso, setSucesso] = useState('');

  // Atualiza o campo que foi alterado sem resetar os outros
  function handleChange(e) {
    setForm({ ...form, [e.target.name]: e.target.value });
  }

  async function handleSubmit(e) {
    e.preventDefault();
    setErro('');
    setSucesso('');

    if (!form.data || !form.local) {
      setErro('Data e local são obrigatórios.');
      return;
    }

    setLoading(true);
    try {
      await createShow({
        data: form.data,
        valorCache: form.valorCache ? parseFloat(form.valorCache) : null,
        local: form.local,
        observacoes: form.observacoes || null,
      });

      setSucesso('Show cadastrado com sucesso!');
      setForm({ data: '', valorCache: '', local: '', observacoes: '' });
      onShowCriado(); // avisa o componente pai para recarregar a lista
    } catch (err) {
      setErro(err.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="card">
      <h2 className="card-title">
        <span className="icon">🎵</span> Cadastrar Show
      </h2>

      <form onSubmit={handleSubmit} className="form">
        <div className="form-row">
          <div className="form-group">
            <label>Data *</label>
            <input
              type="date"
              name="data"
              value={form.data}
              onChange={handleChange}
              className="input"
            />
          </div>

          <div className="form-group">
            <label>Cachê (R$)</label>
            <input
              type="number"
              name="valorCache"
              value={form.valorCache}
              onChange={handleChange}
              placeholder="Deixe vazio se não definido"
              className="input"
              min="0"
              step="0.01"
            />
          </div>
        </div>

        <div className="form-group">
          <label>Local *</label>
          <input
            type="text"
            name="local"
            value={form.local}
            onChange={handleChange}
            placeholder="Ex: Chalezinho, Ouro Minas..."
            className="input"
          />
        </div>

        <div className="form-group">
          <label>Observações</label>
          <input
            type="text"
            name="observacoes"
            value={form.observacoes}
            onChange={handleChange}
            placeholder="Ex: Show das 01:30"
            className="input"
          />
        </div>

        {erro && <div className="alert alert-erro">{erro}</div>}
        {sucesso && <div className="alert alert-sucesso">{sucesso}</div>}

        <button type="submit" className="btn btn-primary" disabled={loading}>
          {loading ? 'Salvando...' : 'Salvar Show'}
        </button>
      </form>
    </div>
  );
}
